Hi, the id is only relevant when posting events or asserting facts over http. By passing an id durable_rules guarantees the event or fact will only be seen once when retried on network failures. Reporting back on `gunicorn`, the http server can be integrated with the code below:

```python
from durable.lang import *

with ruleset('animal'):
    @when_all(c.first << (m.verb == 'eats') & (m.predicate == 'flies'),
              (m.verb == 'lives') & (m.predicate == 'water') & (m.subject == c.first.subject))
    def frog(c):
        c.assert_fact({ 'subject': c.first.subject, 'verb': 'is', 'predicate': 'frog' })

    @when_all(c.first << (m.verb == 'eats') & (m.predicate == 'flies'),
              (m.verb == 'lives') & (m.predicate == 'land') & (m.subject == c.first.subject))
    def chameleon(c):
        c.assert_fact({ 'subject': c.first.subject, 'verb': 'is', 'predicate': 'chameleon' })

    @when_all((m.verb == 'eats') & (m.predicate == 'worms'))
    def bird(c):
        c.assert_fact({ 'subject': c.m.subject, 'verb': 'is', 'predicate': 'bird' })

    @when_all((m.verb == 'is') & (m.predicate == 'frog'))
    def green(c):
        c.assert_fact({ 'subject': c.m.subject, 'verb': 'is', 'predicate': 'green' })

    @when_all((m.verb == 'is') & (m.predicate == 'chameleon'))
    def grey(c):
        c.assert_fact({ 'subject': c.m.subject, 'verb': 'is', 'predicate': 'grey' })

    @when_all((m.verb == 'is') & (m.predicate == 'bird'))
    def black(c):
        c.assert_fact({ 'subject': c.m.subject, 'verb': 'is', 'predicate': 'black' })

    @when_all(+m.subject)
    def output(c):
        print ('Fact: {0} {1} {2}'.format(c.m.subject, c.m.verb, c.m.predicate))

# caching the rules_app
rules_app = None
def run_app(host, application):
    global rules_app
    rules_app = application

# delegating all calls to the rules_app
def app(environ, start_response):
    return rules_app.__call__(environ, start_response)

run_server(run_app)
```
What is very cool about this is you can start several workers by running the command (the code above was saved as unitest.py):  

`gunicorn --workers=2 unitest:app`   

You can see the ruleset running by doing:

`curl -H "content-type: application/json" -X POST -d '{"subject": "Tweety", "verb": "eats", "predicate": "worms"}' http://localhost:8000/animal/facts`  

`curl -H "content-type: application/json" -X POST -d '{"subject": “Kermit”, "verb": "eats", "predicate": "flies"}' http://localhost:8000/animal/facts`  

`curl -H "content-type: application/json" -X POST -d '{"subject": "Kermit", "verb": "lives", "predicate": "water"}' http://localhost:8000/animal/facts`

