    from flask.ext.login import login_user
    # flask-user user_manager instance for app
    from .ext import user_manager

    def custom_login(password, username=None, email=None):
        user = None
        if email:
            user = user_manager.find_user_by_email(email)
        elif username:
            user = user_manager.find_user_by_username(username)
        
        if not user:
            return False

        if not user_manager.verify_password(password, user):
            return False

        return login_user(user, remember=True)

