def print_items(items, indent):
    for item in items:
        if item.is_symbol():
          #if item.get_config().get_srctree()is not None: # tried others as well
          if item.get_config().get_config_header() is not None:
            #print_with_indent("config {0}".format(item.get_name())+" "+item.get_config().get_config_filename(), indent)
