I ended up using this class and importing an instance of it in my flask app:

```
from random import shuffle
from flask_simpleldap import LDAP
from functools import wraps
from flask import current_app


class LDAPContainer(object):
    def __init__(self):
        self.ldap_hosts = []
        self.ldap = None

    def init_app(self, app):
        if app is not None:
            hosts = app.config['LDAP_HOSTS'].replace(" ", "").split(",")
            self.ldap = LDAP(app)
            for host in hosts:
                print "adding %s" % host
                app.config['LDAP_HOST'] = host
                self.ldap_hosts.append(host)

    def get_random_order_ldap(self):
        ldap_index_list = range(0, len(self.ldap_hosts))
        shuffle(ldap_index_list)
        return ldap_index_list

    def require_auth(self, func):
        @wraps(func)
        def wrapped(*args, **kwargs):
            for i in self.get_random_order_ldap():
                try:
                    current_app.config['LDAP_HOST'] = self.ldap_hosts[i]
                    r = self.ldap.basic_auth_required(func)
                    return r(*args, **kwargs)
                except Exception as e:
                    print "Error: %s - LDAP host: %s" % (e.message, self.ldap_hosts[i])
                else:
                    return None
        return wrapped


auth = LDAPContainer()
```

Then all I needed to to was add the `@auth.require_auth` decorator to any views I want to protect.

