@agurfinkel Sort of. The current implementation does not implement any kind of virtual interface (which could be easily added if you want one), but allows compile-time polymorphism by way of templates:

```
// already possible with the old implementations
template<typename T>
void printall(T const& iterable) {
    for(auto const& x : iterable) std::cout << x;
}
```

```
// only possible with the new implementation
template<typename SZ, SZ INITIAL_SIZE>
unsigned sum(buffer<unsigned, SZ, INITIAL_SIZE> const& buff) {
    unsigned sum = 0;
    for(auto const& x : buff) sum += x;
    return sum
}
```

class MyBoolWidget(Widget):
    TRUE_VALUES = ["True", "ja", "Ja", "x", "1", 1]
    FALSE_VALUE = ["False","nein","Nein", "0", ""]

    def render(self, value, obj):
        if value is None:
            return ""
        if value == False:
            return "nein"
        else:
            return "ja"

    def clean(self, value, row):
        cleaned = value.strip().split()
        if not cleaned:
            return None
        elif cleaned[0] in self.TRUE_VALUES:
            return True
        else:
