```
#if PY_MAJOR_VERSION < 3
if (func && PyMethod_Check(func.ptr()))
    func = PyMethod_GET_FUNCTION(func.ptr());
#endif

std::function<Return(Args..)> *myFunc;

if (func && PyCFunction_Check(func.ptr())) {
    py::capsule rec_capsule(PyCFunction_GetSelf(func.ptr()), true);
    auto chain = (py::detail::function_record *) rec_capsule;
    myFunc = chain->data;
}
```

